import axios from "axios";
import toast from "react-hot-toast";

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:5000/api/v1",
  timeout: 30000,
  headers: { "Content-Type": "application/json" },
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem("accessToken");
  if (token) config.headers.Authorization = "Bearer " + token;
  return config;
}, Promise.reject);

api.interceptors.response.use(
  (res) => res,
  async (error) => {
    const msg = error.response?.data?.message || "Something went wrong";
    if (error.response?.status !== 401) toast.error(msg);
    return Promise.reject(error);
  }
);

export const authAPI = {
  login: (data) => api.post("/auth/login", data),
  logout: () => api.post("/auth/logout"),
  me: () => api.get("/auth/me"),
};
export const employeeAPI = {
  getAll: (params) => api.get("/employees", { params }),
  getById: (id) => api.get("/employees/" + id),
  create: (data) => api.post("/employees", data),
  update: (id, data) => api.put("/employees/" + id, data),
  delete: (id) => api.delete("/employees/" + id),
  getStats: () => api.get("/employees/stats"),
  getAttritionRisk: (id) => api.get("/employees/" + id + "/attrition-risk"),
};
export const recruitmentAPI = {
  getJobs: (params) => api.get("/recruitment/jobs", { params }),
  getApplications: (params) => api.get("/recruitment/applications", { params }),
  submitApplication: (data) => api.post("/recruitment/applications", data),
  screenApplication: (id) => api.post("/recruitment/applications/" + id + "/screen"),
  bulkScreen: (jobId) => api.post("/recruitment/applications/bulk-screen", { jobId }),
  updateStatus: (id, data) => api.patch("/recruitment/applications/" + id + "/status", data),
  getStats: () => api.get("/recruitment/stats"),
};
export const payrollAPI = {
  getAll: (params) => api.get("/payroll", { params }),
  generate: (data) => api.post("/payroll/generate", data),
  getSummary: (params) => api.get("/payroll/summary", { params }),
  getEmployeePayroll: (empId, params) => api.get("/payroll/employee/" + empId, { params }),
  approve: (id) => api.patch("/payroll/" + id + "/approve"),
  bulkApprove: (data) => api.post("/payroll/bulk-approve", data),
};
export const leaveAPI = {
  getAll: (params) => api.get("/leave/requests", { params }),
  create: (data) => api.post("/leave/requests", data),
  approve: (id) => api.patch("/leave/requests/" + id + "/approve"),
  reject: (id, data) => api.patch("/leave/requests/" + id + "/reject", data),
  getBalance: (empId, params) => api.get("/leave/balance/" + empId, { params }),
  getCalendar: (params) => api.get("/leave/calendar", { params }),
};
export const aiAPI = {
  chatbot: (message) => api.post("/ai/chatbot", { message }),
  generateJD: (data) => api.post("/ai/generate-jd", data),
  screenResume: (data) => api.post("/ai/screen-resume", data),
  attritionReport: () => api.get("/ai/attrition-report"),
  workforceInsights: () => api.post("/ai/workforce-insights"),
};
export const departmentAPI = { getAll: () => api.get("/departments") };
export default api;
